import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { DashboardStats, Opportunity, STAGE_META } from '../../models/models';

interface StatCard {
  key: string;
  label: string;
  value: number;
  link: string;
  accent: string;
  money?: boolean;
}

@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './dashboard.component.html',
  styleUrl: './dashboard.component.css',
})
export class DashboardComponent {
  readonly stageMeta = STAGE_META;

  stats = signal<DashboardStats>({
    accounts: 12,
    contacts: 34,
    opportunities: 21,
    leads: 15,
    tasks: 18,
    openPipeline: 1284000,
    wonThisQuarter: 486000,
  });

  recentOpportunities = signal<Opportunity[]>([
    { id: 'o1', name: 'Acme — Platform Renewal', accountId: 'a1', accountName: 'Acme Corporation', stage: 'NEGOTIATION', amount: 120000, closeDate: '2026-08-15', probability: 75, owner: 'Demo Admin' },
    { id: 'o2', name: 'Globex Data Migration', accountId: 'a2', accountName: 'Globex Industries', stage: 'PROPOSAL', amount: 84000, closeDate: '2026-07-30', probability: 60, owner: 'Priya Nair' },
    { id: 'o3', name: 'Initech Security Suite', accountId: 'a3', accountName: 'Initech', stage: 'QUALIFICATION', amount: 45000, closeDate: '2026-09-05', probability: 40, owner: 'Marco Diaz' },
    { id: 'o4', name: 'Umbrella Analytics Rollout', accountId: 'a4', accountName: 'Umbrella Health', stage: 'PROSPECTING', amount: 210000, closeDate: '2026-10-12', probability: 20, owner: 'Demo Admin' },
    { id: 'o5', name: 'Soylent Cloud Expansion', accountId: 'a5', accountName: 'Soylent Foods', stage: 'CLOSED_WON', amount: 156000, closeDate: '2026-06-28', probability: 100, owner: 'Priya Nair' },
  ]);

  get cards(): StatCard[] {
    const s = this.stats();
    return [
      { key: 'accounts', label: 'Accounts', value: s.accounts, link: '/accounts', accent: 'var(--stage-qualification)' },
      { key: 'contacts', label: 'Contacts', value: s.contacts, link: '/contacts', accent: 'var(--stage-needs)' },
      { key: 'opportunities', label: 'Opportunities', value: s.opportunities, link: '/opportunities', accent: 'var(--stage-proposal)' },
      { key: 'leads', label: 'Leads', value: s.leads, link: '/leads', accent: 'var(--stage-won)' },
      { key: 'tasks', label: 'Open Tasks', value: s.tasks, link: '/tasks', accent: 'var(--stage-negotiation)' },
    ];
  }

  stageLabel(key: string): string {
    return this.stageMeta.find((s) => s.key === key)?.label ?? key;
  }
  stageColor(key: string): string {
    return this.stageMeta.find((s) => s.key === key)?.color ?? 'var(--color-text-muted)';
  }
}
